#include <bits/stdc++.h>
#define fr first
#define sc second
using namespace std;
typedef pair<int,int> pii;

const int N=3e5+10;

int Gcd(int a,int b){
    return abs(!b?a:Gcd(b,a%b));
}

int n,m,a[N],lst[N];
map<int,int> mp;
set<pii> st;

struct Node{
    int mn,mx,gcd,mxl,l;
    Node operator+(Node x){
        Node res;
        res.mn=min(mn,x.mn);
        res.mx=max(mx,x.mx);
        res.gcd=Gcd(Gcd(gcd,x.gcd),a[x.l]-a[l]);
        res.mxl=max(mxl,x.mxl);
        res.l=l;
        return res;
    }
}t[N<<2];

void build(int cur,int l,int r){
    if(l==r){
        t[cur]={a[l],a[l],0,lst[l],l};
        return;
    }
    int mid=l+r>>1;
    build(cur*2,l,mid);
    build(cur*2+1,mid+1,r);
    t[cur]=t[cur*2]+t[cur*2+1];
}

void modify(int cur,int l,int r,int x){
    if(l==r){
        t[cur]={a[l],a[l],0,lst[l],l};
        return;
    }
    int mid=l+r>>1;
    if(x<=mid)
        modify(cur*2,l,mid,x);
    else
        modify(cur*2+1,mid+1,r,x);
    t[cur]=t[cur*2]+t[cur*2+1];
}

Node query(int cur,int l,int r,int x,int y){
    if(x<=l && r<=y)
        return t[cur];
    int mid=l+r>>1;
    if(y<=mid)
        return query(cur*2,l,mid,x,y);
    if(x>mid)
        return query(cur*2+1,mid+1,r,x,y);
    return query(cur*2,l,mid,x,y)+query(cur*2+1,mid+1,r,x,y);
}

int main(){
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
        scanf("%d",&a[i]);
    for(int i=1;i<=n;i++){
        lst[i]=mp[a[i]];
        mp[a[i]]=i;
        st.insert(make_pair(a[i],i));
    }
    build(1,1,n);
    int cnt=0;
    while(m--){
        int op,x,y,k;
        scanf("%d%d%d",&op,&x,&y);
        x^=cnt,y^=cnt;
        if(op==1){
            auto it=st.find(make_pair(a[x],x));
            it++;
            if(it!=st.end() && (*it).fr==a[x]){
                lst[(*it).sc]=lst[x];
                modify(1,1,n,(*it).sc);
            }
            a[x]=y;
            st.insert(make_pair(a[x],x));
            it=st.find(make_pair(a[x],x));
            if(it!=st.begin()){
                it--;
                if((*it).fr==a[x])
                    lst[x]=(*it).sc;
                else
                    lst[x]=0;
                it++;
            }
            modify(1,1,n,x);
            it++;
            if(it!=st.end() && (*it).fr==a[x]){
                lst[(*it).sc]=x;
                modify(1,1,n,(*it).sc);
            }
        }else{
            scanf("%d",&k);
            k^=cnt;
            if(x==y){
                puts("Yes");
                cnt++;
                continue;
            }
            Node tmp=query(1,1,n,x,y);
            if(k==0){
                if(tmp.mn==tmp.mx){
                    puts("Yes");
                    cnt++;
                }else
                    puts("No");
            }else{
                if(tmp.mx-tmp.mn==(y-x)*k && tmp.gcd==k && tmp.mxl<x){
                    puts("Yes");
                    cnt++;
                }else
                    puts("No");
            }
        }
    }
    return 0;
}
